+		const made = await makeServer();
+		fastify = made.fastify;
+		manager = made.manager;
+	});
+
+	afterEach(async () => {
+		manager.stop();
+		await fastify.close();
+	});
+
+	it("returns 404 when sending to a bin that does not exist", async () => {
+		const res = await fastify.inject({ method: "POST", url: "/b/missing" });
